  ('disabled-0a2fc18c-moex-00144', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-112-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '關於消費者剩餘的敘述，下列何者正確？', '["消費者剩餘是位於供給曲線與價格線之間的區域", "消費者剩餘愈大，代表愈多消費者可以買到該項產品，且是以愈高的價 格買到", "消費者剩餘主要是衡量「消費者願付價格與實付價格的差異」，因此「多 少人可以買到該項產品」並不在其計算之列", "當廠商進行第一級差別取價時，會將消費者剩餘全數轉換為生產者剩餘"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "ec91441b2ca1", "answer_pdf_sha1": "79ebb3660238", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "405", "s": "0905", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
